import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 日輪 } from '../bujian/sanmaya.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛光 = (bi) => 菩薩坐身(bi, {
    臂(bi, 筆) {
        const { M, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 尊右臂：前臂橫入，仰掌承日輪於胸下
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-7.3, 41.7], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        衣(() => {
            // 仰掌淺盂
            M(-10.7, 41.4);
            Qk(-8.6, 42.4, -6.5, 41.7);
            S();
            M(-10.4, 42.1);
            Qk(-8.6, 42.9, -6.9, 42.3);
            S();
            細(() => {
                for (const t of [0, 1, 2]) {
                    M(-10.2 + t * 1.15, 41.15 - t * 0.1);
                    Qk(-9.9 + t * 1.15, 40.8 - t * 0.1, -9.5 + t * 1.15, 40.65 - t * 0.1);
                    S();
                }
            });
        });
        日輪(bi, -8.7, 38.0, 0.78);
        // 尊左臂：前臂垂，拳安於腰股之際
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [13.0, 45.6], { 寬根: 2.4, 寬梢: 1.8, 弓: -0.3, 肘帽: false })));
        側拳(bi, 12.8, 47.9, Math.PI / 2, 1.05, -1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-11.7, 40.4, -10.9, 41.3, -10.1, 42.1], [-11.2, 39.8, -10.4, 40.7, -9.6, 41.5]], [-10.7, 40.8]);
            腕釧(bi, [[11.9, 44.9, 13.0, 45.4, 14.1, 45.0], [11.8, 45.8, 12.9, 46.3, 14.0, 45.9]], [12.9, 45.8]);
        });
    },
});
